import type { FeatureCollection } from 'geojson';
import { isUndefined } from 'lodash-es';

import { CDN_BASE_PATH } from '../constants.js';

const cache = new Map<string, FeatureCollection>();

const MAPS_WITH_DISPUTED_BORDERS = ['IN', 'IL', 'CN', 'MA'];

const getWorldViewParam = (countryCode: string): string =>
  MAPS_WITH_DISPUTED_BORDERS.includes(countryCode) ? `${countryCode}/` : '';

export const fetchWorldViewFeatures = async (
  tenantCountryCode: string,
): Promise<FeatureCollection> => {
  const worldViewParam = getWorldViewParam(tenantCountryCode);

  const cacheKey = worldViewParam || 'default';

  let features = cache.get(cacheKey);

  if (isUndefined(features)) {
    const res = await fetch(
      `${CDN_BASE_PATH}${worldViewParam}WORLD-COUNTRIES.json`,
    );

    features = (await res.json()) as FeatureCollection;

    cache.set(cacheKey, features);
  }

  return features;
};

export const fetchCountryFeatures = async (
  tenantCountryCode: string,
  regionCode: string,
): Promise<FeatureCollection> => {
  const worldViewParam = getWorldViewParam(tenantCountryCode);

  const cacheKey = `${worldViewParam || 'default'}-${regionCode}`;

  let features = cache.get(cacheKey);

  if (isUndefined(features)) {
    const res = await fetch(
      `${CDN_BASE_PATH}${worldViewParam}${regionCode}.json`,
    );

    features = (await res.json()) as FeatureCollection;

    cache.set(cacheKey, features);
  }

  return features;
};

/**
 * @internal
 * Only used in unit tests to reset the map features cache
 */
export const _clearCache = () => {
  cache.clear();
};
